import{_ as i,c as l,o as r,ah as t,ai as e}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"91GIT - محطة GitHub الصينية","description":"","frontmatter":{},"headers":[],"relativePath":"ar/91git.md","filePath":"ar/91git.md"}'),n={name:"ar/91git.md"};function o(s,a,h,d,c,_){return r(),l("div",null,a[0]||(a[0]=[t('<h1 id="_91git-محطة-github-الصينية" tabindex="-1">91GIT - محطة GitHub الصينية <a class="header-anchor" href="#_91git-محطة-github-الصينية" aria-label="Permalink to “91GIT - محطة GitHub الصينية”">​</a></h1><p><strong>رابط الوصول:</strong> <a href="https://91git.com/" target="_blank" rel="noreferrer">https://91git.com/</a></p><h2 id="_01-1-نظرة-عامة-على-المشروع" tabindex="-1">01.1- نظرة عامة على المشروع <a class="header-anchor" href="#_01-1-نظرة-عامة-على-المشروع" aria-label="Permalink to “01.1- نظرة عامة على المشروع”">​</a></h2><p>محطة GitHub الصينية —— ابحث عن مستودعات GitHub بنقرة واحدة، وقم بتعبئة التعليمات البرمجية المصدر وأصول الإصدار تلقائيًا، وقم بإنشاء ملفات مضغوطة للتنزيل.</p><p>تم تصميمه خصيصًا لبيئة الشبكة المحلية، مما يساعد المطورين على الوصول السريع إلى موارد مشروع GitHub.</p><p><img src="'+e+'" alt="alt text"></p><h2 id="_01-2-الميزات" tabindex="-1">01.2- الميزات <a class="header-anchor" href="#_01-2-الميزات" aria-label="Permalink to “01.2- الميزات”">​</a></h2><ul><li>🔍 <strong>البحث بالكلمات الرئيسية</strong> - ابحث عن مستودعات GitHub بالكلمات الرئيسية، ورتب حسب عدد النجوم</li><li>📥 <strong>التعبئة بنقرة واحدة</strong> - قم بتنزيل التعليمات البرمجية المصدر + أصول الإصدار تلقائيًا، وإنشاء ملف مضغوط مشفر مزدوج</li><li>🔥 <strong>الأكثر شيوعًا على GitHub</strong> - عرض أفضل 10 مستودعات جديدة ذات نجوم عالية تم إنشاؤها هذا الأسبوع</li><li>📊 <strong>الأكثر شيوعًا على الموقع</strong> - عرض المستودعات التي تم تعبئتها بشكل متكرر في اليوم/الشهر</li><li>⏱️ <strong>التنظيف التلقائي</strong> - يتم حذف ملفات الحزمة تلقائيًا بعد 3 دقائق إذا لم يتم تنزيلها، لتوفير مساحة الخادم</li></ul><h2 id="_01-3-المكدس-التقني" tabindex="-1">01.3- المكدس التقني <a class="header-anchor" href="#_01-3-المكدس-التقني" aria-label="Permalink to “01.3- المكدس التقني”">​</a></h2><ul><li><strong>الواجهة الأمامية</strong>: React + TypeScript + Vite + Tailwind CSS</li><li><strong>الرسوم المتحركة</strong>: Framer Motion</li><li><strong>الخلفية</strong>: Node.js + Express</li><li><strong>التعبئة</strong>: archiver (ZIP)</li><li><strong>التشفير</strong>: AES-256 + كلمة مرور ZIP</li></ul><h2 id="_01-4-سيناريوهات-الاستخدام" tabindex="-1">01.4- سيناريوهات الاستخدام <a class="header-anchor" href="#_01-4-سيناريوهات-الاستخدام" aria-label="Permalink to “01.4- سيناريوهات الاستخدام”">​</a></h2><h3 id="للمطورين" tabindex="-1">للمطورين <a class="header-anchor" href="#للمطورين" aria-label="Permalink to “للمطورين”">​</a></h3><ul><li>الحصول السريع على التعليمات البرمجية المصدر لمشاريع GitHub</li><li>تنزيل أصول الإصدار الكاملة</li><li>تعبئة موارد المشروع للمشاركة</li></ul><h3 id="للباحثين" tabindex="-1">للباحثين <a class="header-anchor" href="#للباحثين" aria-label="Permalink to “للباحثين”">​</a></h3><ul><li>تنزيل أدوات البحث بشكل مجمع</li><li>أرشفة المشاريع مفتوحة المصدر</li><li>بناء مكتبة موارد محلية</li></ul><h3 id="للمستخدمين-المؤسسيين" tabindex="-1">للمستخدمين المؤسسيين <a class="header-anchor" href="#للمستخدمين-المؤسسيين" aria-label="Permalink to “للمستخدمين المؤسسيين”">​</a></h3><ul><li>مشاركة أدوات التطوير داخليًا</li><li>مزامنة موارد الفريق</li><li>النشر في بيئات غير متصلة بالإنترنت</li></ul><h2 id="_01-5-الأمان" tabindex="-1">01.5- الأمان <a class="header-anchor" href="#_01-5-الأمان" aria-label="Permalink to “01.5- الأمان”">​</a></h2><ul><li>✅ حماية تشفير مزدوجة</li><li>✅ تنظيف تلقائي للملفات</li><li>✅ لا يتم جمع بيانات المستخدم</li><li>✅ بروتوكول نقل آمن</li></ul><h2 id="_01-6-الملاحظات" tabindex="-1">01.6- الملاحظات <a class="header-anchor" href="#_01-6-الملاحظات" aria-label="Permalink to “01.6- الملاحظات”">​</a></h2><p>إذا كانت لديك أي أسئلة أو اقتراحات، فيرجى الاتصال بنا عبر:</p><ul><li>قضايا GitHub</li><li>البريد الإلكتروني</li><li>خدمة العملاء عبر الإنترنت</li></ul><hr><p><strong>إخلاء المسؤولية</strong>: يُرجى استخدام هذه الأداة لأغراض التعلم والبحث فقط. يرجى الالتزام بشروط استخدام GitHub واللوائح ذات الصلة.</p>',24)]))}const u=i(n,[["render",o]]);export{b as __pageData,u as default};
